{"content": "     1|/**
     2| * @module dispatcher
     3| * @description Route parsed GSD tasks to the correct agent platform:
     4| * Paperclip (wakeup API), OpenClaw (relay), or Hermes (direct execution).
     5| * Supports wave-aware sequential dispatch.
     6| */
     7|
     8|import { readFile } from 'node:fs/promises';
     9|import { groupByWave } from './parser.js';
    10|
    11|// ─── Agent Platform Mappings ───────────────────────────────────────────────────
    12|
    13|/** Paperclip agent UUIDs keyed by assignee slug */
    14|const PAPERCLIP_AGENTS = {
    15|  'coo':                '42691074-c6d8-4175-a1a7-6303eec10c51',
    16|  'COO':                '42691074-c6d8-4175-a1a7-6303eec10c51',
    17|  'marketing-director': 'c10cfd37-5557-4477-a42d-bdb1fbd80465',
    18|  'Marketing-Director': 'c10cfd37-5557-4477-a42d-bdb1fbd80465',
    19|  'intake-specialist':  'c2202e51-28bf-4a5e-a0d4-2ec3424c5f14',
    20|  'Intake-Specialist':  'c2202e51-28bf-4a5e-a0d4-2ec3424c5f14',
    21|  'follow-up-agent':    '5845ae76-431f-47ec-bad0-d36f8bb42db8',
    22|  'Follow-up-Agent':    '5845ae76-431f-47ec-bad0-d36f8bb42db8',
    23|  'matchmaker':         '48223b46-63a9-4fc9-b110-f1a69db47bfe',
    24|  'Matchmaker':         '48223b46-63a9-4fc9-b110-f1a69db47bfe',
    25|};
    26|
    27|/** Assignee slugs that resolve to OpenClaw agents (relayed via relay server) */
    28|const OPENCLAW_AGENTS = new Set([
    29|  'openclaw/main',
    30|  'openclaw/coder',
    31|  'roscoe',
    32|  'coder',
    33|]);
    34|
    35|/** Assignee slugs that resolve to Hermes direct execution */
    36|const HERMES_AGENTS = new Set([
    37|  'hermes-ceo',
    38|  'hermes',
    39|]);
    40|
    41|// ─── Auth / Config ─────────────────────────────────────────────────────────────
    42|
    43|const PAPERCLIP_BASE = 'https://agents.lawyerincorporated.com';
    44|const PAPERCLIP_AUTH=***
    45|  email: 'aaron@lawyerincorporated.com',
    46|  password: 'Beekerks50$',
    47|};
    48|
    49|const RELAY_BASE = 'https://relay.lawyerincorporated.com';
    50|const RELAY_SECRET='29c3a9...847c';
    51|
    52|/** Cached Paperclip auth token */
    53|let _paperclipToken = null;
    54|let _paperclipTokenExpiry = 0;
    55|
    56|/**
    57| * @typedef {Object} DispatchResult
    58| * @property {string} taskId
    59| * @property {string} assignee
    60| * @property {'paperclip'|'openclaw'|'hermes'|'unknown'} platform
    61| * @property {boolean} success
    62| * @property {number|null} status
    63| * @property {any} response
    64| * @property {string|null} error
    65| */
    66|
    67|// ─── Platform Detection ────────────────────────────────────────────────────────
    68|
    69|/**
    70| * Determine which platform an assignee belongs to.
    71| *
    72| * @param {string} assignee - The task assignee slug
    73| * @returns {'paperclip'|'openclaw'|'hermes'|'unknown'}
    74| */
    75|export function detectPlatform(assignee) {
    76|  const slug = assignee.toLowerCase();
    77|  if (HERMES_AGENTS.has(slug) || HERMES_AGENTS.has(assignee)) return 'hermes';
    78|  if (OPENCLAW_AGENTS.has(slug) || OPENCLAW_AGENTS.has(assignee)) return 'openclaw';
    79|  if (PAPERCLIP_AGENTS[assignee] || PAPERCLIP_AGENTS[slug]) return 'paperclip';
    80|  return 'unknown';
    81|}
    82|
    83|// ─── Paperclip Auth ────────────────────────────────────────────────────────────
    84|
    85|/**
    86| * Authenticate with Paperclip and cache the bearer token.
    87| *
    88| * @returns {Promise<string>} Bearer token
    89| */
    90|async function getPaperclipToken() {
    91|  if (_paperclipToken && Date.now() < _paperclipTokenExpiry) {
    92|    return _paperclipToken;
    93|  }
    94|
    95|  const res = await fetch(`${PAPERCLIP_BASE}/api/auth/login`, {
    96|    method: 'POST',
    97|    headers: { 'Content-Type': 'application/json' },
    98|    body: JSON.stringify(PAPERCLIP_AUTH),
    99|  });
   100|
   101|  if (!res.ok) {
   102|    const text = await res.text();
   103|    throw new Error(`Paperclip auth failed (${res.status}): ${text}`);
   104|  }
   105|
   106|  const data = await res.json();
   107|  _paperclipToken = data.token || data.access_token || data.jwt;
   108|  // Cache for 55 minutes
   109|  _paperclipTokenExpiry = Date.now() + 55 * 60 * 1000;
   110|  return _paperclipToken;
   111|}
   112|
   113|// ─── Dispatch Functions ────────────────────────────────────────────────────────
   114|
   115|/**
   116| * Dispatch a task to a Paperclip agent via the wakeup API.
   117| *
   118| * @param {import('./parser.js').Task} task - The task to dispatch
   119| * @returns {Promise<DispatchResult>}
   120| */
   121|export async function dispatchToPaperclip(task) {
   122|  const agentId = PAPERCLIP_AGENTS[task.assignee] || PAPERCLIP_AGENTS[task.assignee.toLowerCase()];
   123|  if (!agentId) {
   124|    return {
   125|      taskId: task.id,
   126|      assignee: task.assignee,
   127|      platform: 'paperclip',
   128|      success: false,
   129|      status: null,
   130|      response: null,
   131|      error: `No Paperclip agent UUID for assignee "${task.assignee}"`,
   132|    };
   133|  }
   134|
   135|  try {
   136|    const token = await getPaperclipToken();
   137|
   138|    const wakeReason = [
   139|      `[GSD Task ${task.id}] ${task.title}`,
   140|      '',
   141|      `Type: ${task.type}`,
   142|      `Description: ${task.description}`,
   143|      '',
   144|      `Verification: ${task.verify}`,
   145|      `Done when: ${task.done}`,
   146|      task.approval ? `Requires approval: ${task.approval}` : '',
   147|    ].filter(Boolean).join('\n');
   148|
   149|    const res = await fetch(`${PAPERCLIP_BASE}/api/agents/${agentId}/wakeup`, {
   150|      method: 'POST',
   151|      headers: {
   152|        'Content-Type': 'application/json',
   153|        'Authorization': `Bearer ${token}`,
   154|      },
   155|      body: JSON.stringify({
   156|        reason: wakeReason,
   157|        task_id: task.id,
   158|        task_type: task.type,
   159|        source: 'gsd-dispatcher',
   160|      }),
   161|    });
   162|
   163|    const body = await res.json().catch(() => res.text());
   164|
   165|    return {
   166|      taskId: task.id,
   167|      assignee: task.assignee,
   168|      platform: 'paperclip',
   169|      success: res.ok,
   170|      status: res.status,
   171|      response: body,
   172|      error: res.ok ? null : `Paperclip wakeup failed (${res.status})`,
   173|    };
   174|  } catch (err) {
   175|    return {
   176|      taskId: task.id,
   177|      assignee: task.assignee,
   178|      platform: 'paperclip',
   179|      success: false,
   180|      status: null,
   181|      response: null,
   182|      error: err.message,
   183|    };
   184|  }
   185|}
   186|
   187|/**
   188| * Dispatch a task to an OpenClaw agent via the relay server.
   189| *
   190| * @param {import('./parser.js').Task} task - The task to dispatch
   191| * @returns {Promise<DispatchResult>}
   192| */
   193|export async function dispatchToOpenClaw(task) {
   194|  // Map assignee to relay target name
   195|  const targetMap = {
   196|    'openclaw/main': 'openclaw-main',
   197|    'openclaw/coder': 'openclaw-coder',
   198|    'roscoe': 'openclaw-main',
   199|    'coder': 'openclaw-coder',
   200|  };
   201|
   202|  const target = targetMap[task.assignee.toLowerCase()] || task.assignee;
   203|
   204|  const chatPayload = [
   205|    `[GSD Task ${task.id}] ${task.title}`,
   206|    '',
   207|    `Type: ${task.type}`,
   208|    `Description: ${task.description}`,
   209|    '',
   210|    `Verification criteria: ${task.verify}`,
   211|    `Done when: ${task.done}`,
   212|    task.approval ? `Requires approval from: ${task.approval}` : '',
   213|  ].filter(Boolean).join('\n');
   214|
   215|  try {
   216|    const res = await fetch(`${RELAY_BASE}/relay/send`, {
   217|      method: 'POST',
   218|      headers: {
   219|        'Content-Type': 'application/json',
   220|        'Authorization': `Bearer ${RELAY_SECRET}`,
   221|      },
   222|      body: JSON.stringify({
   223|        target,
   224|        message: chatPayload,
   225|        metadata: {
   226|          task_id: task.id,
   227|          task_type: task.type,
   228|          source: 'gsd-dispatcher',
   229|          wave: task.wave,
   230|        },
   231|      }),
   232|    });
   233|
   234|    const body = await res.json().catch(() => res.text());
   235|
   236|    return {
   237|      taskId: task.id,
   238|      assignee: task.assignee,
   239|      platform: 'openclaw',
   240|      success: res.ok,
   241|      status: res.status,
   242|      response: body,
   243|      error: res.ok ? null : `Relay send failed (${res.status})`,
   244|    };
   245|  } catch (err) {
   246|    return {
   247|      taskId: task.id,
   248|      assignee: task.assignee,
   249|      platform: 'openclaw',
   250|      success: false,
   251|      status: null,
   252|      response: null,
   253|      error: err.message,
   254|    };
   255|  }
   256|}
   257|
   258|/**
   259| * Handle a task assigned to Hermes for direct execution.
   260| * Returns the task payload for the calling orchestrator to execute.
   261| *
   262| * @param {import('./parser.js').Task} task - The task to handle
   263| * @returns {Promise<DispatchResult>}
   264| */
   265|export async function dispatchToHermes(task) {
   266|  return {
   267|    taskId: task.id,
   268|    assignee: task.assignee,
   269|    platform: 'hermes',
   270|    success: true,
   271|    status: 200,
   272|    response: {
   273|      action: 'execute_directly',
   274|      task,
   275|    },
   276|    error: null,
   277|  };
   278|}
   279|
   280|// ─── Core Dispatch Router ──────────────────────────────────────────────────────
   281|
   282|/**
   283| * Dispatch a single task to the appropriate platform.
   284| *
   285| * @param {import('./parser.js').Task} task
   286| * @param {Object} [options]
   287| * @param {boolean} [options.dryRun=false] - If true, return what would be dispatched without calling APIs
   288| * @returns {Promise<DispatchResult>}
   289| */
   290|export async function dispatchTask(task, options = {}) {
   291|  const platform = detectPlatform(task.assignee);
   292|
   293|  if (options.dryRun) {
   294|    return {
   295|      taskId: task.id,
   296|      assignee: task.assignee,
   297|      platform,
   298|      success: true,
   299|      status: null,
   300|      response: { dryRun: true, wouldDispatchTo: platform },
   301|      error: null,
   302|    };
   303|  }
   304|
   305|  switch (platform) {
   306|    case 'paperclip':
   307|      return dispatchToPaperclip(task);
   308|    case 'openclaw':
   309|      return dispatchToOpenClaw(task);
   310|    case 'hermes':
   311|      return dispatchToHermes(task);
   312|    default:
   313|      return {
   314|        taskId: task.id,
   315|        assignee: task.assignee,
   316|        platform: 'unknown',
   317|        success: false,
   318|        status: null,
   319|        response: null,
   320|        error: `Unknown platform for assignee "${task.assignee}". Cannot route.`,
   321|      };
   322|  }
   323|}
   324|
   325|// ─── Wave-Aware Execution ──────────────────────────────────────────────────────
   326|
   327|/**
   328| * @typedef {Object} WaveResult
   329| * @property {number} wave
   330| * @property {DispatchResult[]} results
   331| * @property {boolean} allSucceeded
   332| */
   333|
   334|/**
   335| * Dispatch all tasks in a plan, wave by wave.
   336| * Dispatches all tasks in wave N in parallel, waits for completion,
   337| * then proceeds to wave N+1.
   338| *
   339| * @param {import('./parser.js').Task[]} tasks - All tasks from a plan
   340| * @param {Object} [options]
   341| * @param {boolean} [options.dryRun=false] - Dry-run mode
   342| * @param {boolean} [options.stopOnWaveFailure=false] - Stop if any task in a wave fails
   343| * @param {(result: WaveResult) => void} [options.onWaveComplete] - Callback after each wave
   344| * @returns {Promise<WaveResult[]>}
   345| */
   346|export async function dispatchByWaves(tasks, options = {}) {
   347|  const waves = groupByWave(tasks);
   348|  const results = [];
   349|
   350|  for (const [waveNum, waveTasks] of waves) {
   351|    // Dispatch all tasks in this wave concurrently
   352|    const waveResults = await Promise.all(
   353|      waveTasks.map(task => dispatchTask(task, { dryRun: options.dryRun }))
   354|    );
   355|
   356|    const waveResult = {
   357|      wave: waveNum,
   358|      results: waveResults,
   359|      allSucceeded: waveResults.every(r => r.success),
   360|    };
   361|
   362|    results.push(waveResult);
   363|
   364|    if (options.onWaveComplete) {
   365|      options.onWaveComplete(waveResult);
   366|    }
   367|
   368|    // Optionally stop on failure
   369|    if (options.stopOnWaveFailure && !waveResult.allSucceeded) {
   370|      break;
   371|    }
   372|  }
   373|
   374|  return results;
   375|}
   376|
   377|/**
   378| * Load routing config from a config.json file and validate assignees.
   379| *
   380| * @param {string} configPath - Path to config.json
   381| * @returns {Promise<Object>} Parsed config
   382| */
   383|export async function loadConfig(configPath) {
   384|  const raw = await readFile(configPath, 'utf-8');
   385|  return JSON.parse(raw);
   386|}
   387|
   388|/**
   389| * High-level: parse a plan file, dispatch all tasks wave-by-wave.
   390| *
   391| * @param {string} planPath - Path to PLAN.md file
   392| * @param {Object} [options]
   393| * @param {boolean} [options.dryRun=false]
   394| * @param {boolean} [options.stopOnWaveFailure=false]
   395| * @param {(result: WaveResult) => void} [options.onWaveComplete]
   396| * @returns {Promise<{meta: import('./parser.js').TaskMeta, waveResults: WaveResult[]}>}
   397| */
   398|export async function executePlan(planPath, options = {}) {
   399|  // Dynamic import to avoid circular dependency issues
   400|  const { parsePlanFile } = await import('./parser.js');
   401|  const plan = await parsePlanFile(planPath);
   402|
   403|  const waveResults = await dispatchByWaves(plan.tasks, options);
   404|
   405|  return {
   406|    meta: plan.meta,
   407|    waveResults,
   408|  };
   409|}
