{"content": "     1|/**
     2| * @module mc-sync
     3| * @description Mission Control synchronization — create and update MC tasks
     4| * from parsed PLAN.md files, sync status from STATE.md changes.
     5| * API: ops.lawyerincorporated.com
     6| */
     7|
     8|const MC_BASE = 'https://ops.lawyerincorporated.com';
     9|const MC_API_KEY='86e061...b33b';
    10|
    11|/** Common headers for all MC API calls */
    12|const MC_HEADERS = {
    13|  'Content-Type': 'application/json',
    14|  'x-api-key': MC_API_KEY,
    15|};
    16|
    17|/**
    18| * Map GSD task status strings to MC pipeline stages.
    19| * MC pipeline: inbox → assigned → in_progress → quality_review → done
    20| */
    21|const STATUS_TO_MC = {
    22|  'planned':     'inbox',
    23|  'assigned':    'assigned',
    24|  'dispatched':  'assigned',
    25|  'in_progress': 'in_progress',
    26|  'blocked':     'in_progress',   // MC doesn't have a blocked state; keep in progress
    27|  'reviewing':   'quality_review',
    28|  'verified':    'quality_review',
    29|  'done':        'done',
    30|  'shipped':     'done',
    31|};
    32|
    33|/**
    34| * @typedef {Object} MCTask
    35| * @property {string} id - MC ticket ref (e.g., "GSD-001")
    36| * @property {string} title
    37| * @property {string} description
    38| * @property {string} status
    39| * @property {string} assignee
    40| * @property {string} taskId - Original PLAN.md task ID
    41| */
    42|
    43|/**
    44| * @typedef {Object} TaskMapping
    45| * @property {string} planTaskId - PLAN.md task ID (e.g., "SEO-01")
    46| * @property {string} mcTicketRef - MC ticket ref (e.g., "GSD-005")
    47| * @property {string} mcTaskId - MC internal ID
    48| */
    49|
    50|// ─── In-memory mapping store ───────────────────────────────────────────────────
    51|
    52|/** @type {Map<string, TaskMapping>} planTaskId → mapping */
    53|const _taskMappings = new Map();
    54|
    55|/**
    56| * Get the task ID mapping store. Useful for persistence.
    57| * @returns {Map<string, TaskMapping>}
    58| */
    59|export function getMappings() {
    60|  return _taskMappings;
    61|}
    62|
    63|/**
    64| * Load mappings from a JSON object (e.g., read from disk).
    65| * @param {TaskMapping[]} mappings
    66| */
    67|export function loadMappings(mappings) {
    68|  _taskMappings.clear();
    69|  for (const m of mappings) {
    70|    _taskMappings.set(m.planTaskId, m);
    71|  }
    72|}
    73|
    74|/**
    75| * Export mappings as a serializable array.
    76| * @returns {TaskMapping[]}
    77| */
    78|export function exportMappings() {
    79|  return [..._taskMappings.values()];
    80|}
    81|
    82|// ─── MC API Helpers ────────────────────────────────────────────────────────────
    83|
    84|/**
    85| * Make an authenticated request to the Mission Control API.
    86| *
    87| * @param {string} path - API path (e.g., "/api/tasks")
    88| * @param {Object} [options] - fetch options override
    89| * @returns {Promise<{ok: boolean, status: number, data: any}>}
    90| */
    91|async function mcFetch(path, options = {}) {
    92|  const url = `${MC_BASE}${path}`;
    93|  try {
    94|    const res = await fetch(url, {
    95|      headers: MC_HEADERS,
    96|      ...options,
    97|    });
    98|
    99|    let data;
   100|    const contentType = res.headers.get('content-type') || '';
   101|    if (contentType.includes('application/json')) {
   102|      data = await res.json();
   103|    } else {
   104|      data = await res.text();
   105|    }
   106|
   107|    return { ok: res.ok, status: res.status, data };
   108|  } catch (err) {
   109|    return { ok: false, status: 0, data: null, error: err.message };
   110|  }
   111|}
   112|
   113|// ─── Task CRUD ─────────────────────────────────────────────────────────────────
   114|
   115|/**
   116| * Create a Mission Control task from a parsed PLAN.md task.
   117| *
   118| * @param {import('./parser.js').Task} task - Parsed task from PLAN.md
   119| * @param {Object} [meta] - Optional plan metadata for context
   120| * @param {string} [meta.phase] - Phase name
   121| * @param {string} [meta.projectId] - MC project ID
   122| * @returns {Promise<{success: boolean, ticketRef: string|null, mcId: string|null, error: string|null}>}
   123| */
   124|export async function createMCTask(task, meta = {}) {
   125|  const description = [
   126|    task.description,
   127|    '',
   128|    `Type: ${task.type}`,
   129|    `Wave: ${task.wave}`,
   130|    task.approval ? `Approval required: ${task.approval}` : '',
   131|    `Verification: ${task.verify}`,
   132|    `Done when: ${task.done}`,
   133|    '',
   134|    `Source: PLAN.md task ${task.id}`,
   135|    meta.phase ? `Phase: ${meta.phase}` : '',
   136|  ].filter(Boolean).join('\n');
   137|
   138|  const payload = {
   139|    title: `[${task.id}] ${task.title}`,
   140|    description,
   141|    status: STATUS_TO_MC[task.status || 'planned'] || 'inbox',
   142|    assignee: task.assignee,
   143|    priority: task.approval === 'aaron' ? 'high' : 'medium',
   144|    tags: [task.type, `wave-${task.wave}`, 'gsd-managed'],
   145|  };
   146|
   147|  if (meta.projectId) {
   148|    payload.project_id = meta.projectId;
   149|  }
   150|
   151|  const result = await mcFetch('/api/tasks', {
   152|    method: 'POST',
   153|    body: JSON.stringify(payload),
   154|  });
   155|
   156|  if (result.ok && result.data) {
   157|    const ticketRef = result.data.ticket_ref || result.data.ticketRef || result.data.id;
   158|    const mcId = result.data.id || result.data._id;
   159|
   160|    // Store mapping
   161|    _taskMappings.set(task.id, {
   162|      planTaskId: task.id,
   163|      mcTicketRef: ticketRef,
   164|      mcTaskId: mcId,
   165|    });
   166|
   167|    return { success: true, ticketRef, mcId, error: null };
   168|  }
   169|
   170|  return {
   171|    success: false,
   172|    ticketRef: null,
   173|    mcId: null,
   174|    error: result.error || `MC API returned ${result.status}: ${JSON.stringify(result.data)}`,
   175|  };
   176|}
   177|
   178|/**
   179| * Update an existing MC task's status.
   180| *
   181| * @param {string} planTaskId - PLAN.md task ID
   182| * @param {string} newStatus - New GSD status (planned, in_progress, done, etc.)
   183| * @param {Object} [extra] - Additional fields to update
   184| * @returns {Promise<{success: boolean, error: string|null}>}
   185| */
   186|export async function updateMCTaskStatus(planTaskId, newStatus, extra = {}) {
   187|  const mapping = _taskMappings.get(planTaskId);
   188|  if (!mapping) {
   189|    return { success: false, error: `No MC mapping found for task "${planTaskId}"` };
   190|  }
   191|
   192|  const mcStatus = STATUS_TO_MC[newStatus] || newStatus;
   193|
   194|  const payload = {
   195|    status: mcStatus,
   196|    ...extra,
   197|  };
   198|
   199|  const result = await mcFetch(`/api/tasks/${mapping.mcTaskId}`, {
   200|    method: 'PATCH',
   201|    body: JSON.stringify(payload),
   202|  });
   203|
   204|  return {
   205|    success: result.ok,
   206|    error: result.ok ? null : `MC update failed (${result.status}): ${JSON.stringify(result.data)}`,
   207|  };
   208|}
   209|
   210|/**
   211| * Get the MC ticket ref for a PLAN.md task ID.
   212| *
   213| * @param {string} planTaskId
   214| * @returns {string|null}
   215| */
   216|export function getTicketRef(planTaskId) {
   217|  const mapping = _taskMappings.get(planTaskId);
   218|  return mapping ? mapping.mcTicketRef : null;
   219|}
   220|
   221|// ─── Bulk Operations ───────────────────────────────────────────────────────────
   222|
   223|/**
   224| * Create MC tasks for all tasks in a parsed plan.
   225| *
   226| * @param {import('./parser.js').ParsedPlan} plan - Parsed plan object
   227| * @param {Object} [options]
   228| * @param {string} [options.projectId] - MC project ID
   229| * @param {boolean} [options.skipExisting=true] - Skip tasks already mapped
   230| * @returns {Promise<{created: number, skipped: number, failed: number, results: Object[]}>}
   231| */
   232|export async function syncPlanToMC(plan, options = {}) {
   233|  const results = [];
   234|  let created = 0, skipped = 0, failed = 0;
   235|
   236|  for (const task of plan.tasks) {
   237|    // Skip if already mapped
   238|    if (options.skipExisting !== false && _taskMappings.has(task.id)) {
   239|      skipped++;
   240|      results.push({ taskId: task.id, action: 'skipped', reason: 'already mapped' });
   241|      continue;
   242|    }
   243|
   244|    const res = await createMCTask(task, {
   245|      phase: plan.meta.phase,
   246|      projectId: options.projectId,
   247|    });
   248|
   249|    if (res.success) {
   250|      created++;
   251|      results.push({ taskId: task.id, action: 'created', ticketRef: res.ticketRef });
   252|    } else {
   253|      failed++;
   254|      results.push({ taskId: task.id, action: 'failed', error: res.error });
   255|    }
   256|  }
   257|
   258|  return { created, skipped, failed, results };
   259|}
   260|
   261|/**
   262| * Sync status updates from a STATE.md task status map to MC.
   263| *
   264| * @param {Object<string, string>} taskStatuses - Map of planTaskId → new status
   265| * @returns {Promise<{updated: number, failed: number, unmapped: number, results: Object[]}>}
   266| */
   267|export async function syncStatusToMC(taskStatuses) {
   268|  const results = [];
   269|  let updated = 0, failed = 0, unmapped = 0;
   270|
   271|  for (const [taskId, status] of Object.entries(taskStatuses)) {
   272|    if (!_taskMappings.has(taskId)) {
   273|      unmapped++;
   274|      results.push({ taskId, action: 'unmapped', status });
   275|      continue;
   276|    }
   277|
   278|    const res = await updateMCTaskStatus(taskId, status);
   279|    if (res.success) {
   280|      updated++;
   281|      results.push({ taskId, action: 'updated', status });
   282|    } else {
   283|      failed++;
   284|      results.push({ taskId, action: 'failed', error: res.error });
   285|    }
   286|  }
   287|
   288|  return { updated, failed, unmapped, results };
   289|}
   290|
   291|/**
   292| * Fetch all MC tasks for a project.
   293| *
   294| * @param {string} [projectId] - MC project ID, or omit for all tasks
   295| * @returns {Promise<{success: boolean, tasks: any[], error: string|null}>}
   296| */
   297|export async function fetchMCTasks(projectId) {
   298|  const path = projectId ? `/api/tasks?project_id=${projectId}` : '/api/tasks';
   299|  const result = await mcFetch(path);
   300|
   301|  if (result.ok) {
   302|    const tasks = Array.isArray(result.data) ? result.data : (result.data?.tasks || []);
   303|    return { success: true, tasks, error: null };
   304|  }
   305|
   306|  return {
   307|    success: false,
   308|    tasks: [],
   309|    error: result.error || `MC fetch failed (${result.status})`,
   310|  };
   311|}
   312|
   313|/**
   314| * Create or get an MC project for a GSD workspace.
   315| *
   316| * @param {string} name - Project name
   317| * @param {string} [description] - Project description
   318| * @returns {Promise<{success: boolean, projectId: string|null, error: string|null}>}
   319| */
   320|export async function ensureMCProject(name, description) {
   321|  const result = await mcFetch('/api/projects', {
   322|    method: 'POST',
   323|    body: JSON.stringify({ name, description: description || `GSD workspace: ${name}` }),
   324|  });
   325|
   326|  if (result.ok && result.data) {
   327|    return {
   328|      success: true,
   329|      projectId: result.data.id || result.data._id,
   330|      error: null,
   331|    };
   332|  }
   333|
   334|  return {
   335|    success: false,
   336|    projectId: null,
   337|    error: result.error || `Failed to create MC project (${result.status})`,
   338|  };
   339|}
