{"content": "     1|/**
     2| * @module parser
     3| * @description Parse PLAN.md files — extract YAML frontmatter and XML task definitions
     4| * into structured objects for the GSD execution engine.
     5| */
     6|
     7|import { readFile, readdir } from 'node:fs/promises';
     8|import { join, basename } from 'node:path';
     9|
    10|/**
    11| * @typedef {Object} TaskMeta
    12| * @property {string} phase
    13| * @property {string} title
    14| * @property {string} goal
    15| * @property {string} status
    16| * @property {string} approval
    17| * @property {number|string} wave
    18| */
    19|
    20|/**
    21| * @typedef {Object} Task
    22| * @property {string} id
    23| * @property {string} type
    24| * @property {string} assignee
    25| * @property {string|number} wave
    26| * @property {string} title
    27| * @property {string} description
    28| * @property {string|null} approval
    29| * @property {string} verify
    30| * @property {string} done
    31| */
    32|
    33|/**
    34| * @typedef {Object} ParsedPlan
    35| * @property {TaskMeta} meta
    36| * @property {string[]} mustBeTrue
    37| * @property {Task[]} tasks
    38| */
    39|
    40|/**
    41| * Parse YAML frontmatter from a markdown string.
    42| * Expects content between opening and closing --- markers.
    43| *
    44| * @param {string} content - Raw markdown content
    45| * @returns {TaskMeta} Parsed frontmatter fields
    46| */
    47|export function parseFrontmatter(content) {
    48|  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
    49|  if (!match) {
    50|    return { phase: '', title: '', goal: '', status: 'planned', approval: 'none', wave: 1 };
    51|  }
    52|
    53|  const yaml = match[1];
    54|  const meta = {};
    55|
    56|  for (const line of yaml.split('\n')) {
    57|    const kvMatch = line.match(/^(\w[\w-]*):\s*(.+)$/);
    58|    if (kvMatch) {
    59|      const key = kvMatch[1].trim();
    60|      let value = kvMatch[2].trim();
    61|      // Strip surrounding quotes
    62|      if ((value.startsWith('"') && value.endsWith('"')) ||
    63|          (value.startsWith("'") && value.endsWith("'"))) {
    64|        value = value.slice(1, -1);
    65|      }
    66|      // Strip inline comments
    67|      value = value.replace(/\s+#\s+.*$/, '');
    68|      // Coerce numbers
    69|      if (/^\d+$/.test(value)) value = parseInt(value, 10);
    70|      meta[key] = value;
    71|    }
    72|  }
    73|
    74|  return {
    75|    phase: meta.phase ?? '',
    76|    title: meta.title ?? '',
    77|    goal: meta.goal ?? '',
    78|    status: meta.status ?? 'planned',
    79|    approval: meta.approval ?? 'none',
    80|    wave: meta.wave ?? 1,
    81|  };
    82|}
    83|
    84|/**
    85| * Extract "Must Be True" items from the markdown.
    86| * Looks for the section header and collects bullet items.
    87| *
    88| * @param {string} content - Raw markdown content
    89| * @returns {string[]} List of must-be-true conditions
    90| */
    91|export function parseMustBeTrue(content) {
    92|  const sectionMatch = content.match(/##\s*Must\s+Be\s+True[^\n]*\n([\s\S]*?)(?=\n##\s|\n<task\s|$)/i);
    93|  if (!sectionMatch) return [];
    94|
    95|  return sectionMatch[1]
    96|    .split('\n')
    97|    .map(line => line.replace(/^[\s-]*/, '').trim())
    98|    .filter(line => line.length > 0);
    99|}
   100|
   101|/**
   102| * Extract the text content of an XML element from a string.
   103| *
   104| * @param {string} xml - XML fragment
   105| * @param {string} tag - Tag name to extract
   106| * @returns {string|null} Inner text or null if not found
   107| */
   108|function extractTag(xml, tag) {
   109|  const re = new RegExp(`<${tag}>(.*?)</${tag}>`, 's');
   110|  const m = xml.match(re);
   111|  return m ? m[1].trim() : null;
   112|}
   113|
   114|/**
   115| * Parse all <task> elements from markdown content.
   116| *
   117| * @param {string} content - Raw markdown content
   118| * @returns {Task[]} Array of parsed task objects
   119| */
   120|export function parseTasks(content) {
   121|  const tasks = [];
   122|  const taskRegex = /<task\s+([^>]*)>([\s\S]*?)<\/task>/g;
   123|  let match;
   124|
   125|  while ((match = taskRegex.exec(content)) !== null) {
   126|    const attrs = match[1];
   127|    const body = match[2];
   128|
   129|    // Parse attributes
   130|    const attrMap = {};
   131|    const attrRegex = /(\w[\w-]*)="([^"]*)"/g;
   132|    let attrMatch;
   133|    while ((attrMatch = attrRegex.exec(attrs)) !== null) {
   134|      attrMap[attrMatch[1]] = attrMatch[2];
   135|    }
   136|
   137|    const task = {
   138|      id: attrMap.id ?? '',
   139|      type: attrMap.type ?? 'code',
   140|      assignee: attrMap.assignee ?? '',
   141|      wave: attrMap.wave ? parseInt(attrMap.wave, 10) : 1,
   142|      title: extractTag(body, 'title') ?? '',
   143|      description: extractTag(body, 'description') ?? '',
   144|      approval: extractTag(body, 'approval') ?? null,
   145|      verify: extractTag(body, 'verify') ?? '',
   146|      done: extractTag(body, 'done') ?? '',
   147|    };
   148|
   149|    tasks.push(task);
   150|  }
   151|
   152|  return tasks;
   153|}
   154|
   155|/**
   156| * Parse a single PLAN.md file into a structured object.
   157| *
   158| * @param {string} filePath - Path to the PLAN.md file
   159| * @returns {Promise<ParsedPlan>} Parsed plan object
   160| */
   161|export async function parsePlanFile(filePath) {
   162|  const content = await readFile(filePath, 'utf-8');
   163|
   164|  return {
   165|    meta: parseFrontmatter(content),
   166|    mustBeTrue: parseMustBeTrue(content),
   167|    tasks: parseTasks(content),
   168|  };
   169|}
   170|
   171|/**
   172| * Parse a PLAN.md string directly (no file read).
   173| *
   174| * @param {string} content - Raw PLAN.md content
   175| * @returns {ParsedPlan} Parsed plan object
   176| */
   177|export function parsePlanContent(content) {
   178|  return {
   179|    meta: parseFrontmatter(content),
   180|    mustBeTrue: parseMustBeTrue(content),
   181|    tasks: parseTasks(content),
   182|  };
   183|}
   184|
   185|/**
   186| * Scan a phase directory for all PLAN.md files and parse them.
   187| *
   188| * @param {string} phaseDir - Path to the phase directory (e.g., phases/01-seo-fixes/)
   189| * @returns {Promise<ParsedPlan[]>} Array of parsed plans
   190| */
   191|export async function parsePhasePlans(phaseDir) {
   192|  const entries = await readdir(phaseDir);
   193|  const planFiles = entries
   194|    .filter(f => f.toUpperCase().includes('PLAN') && f.endsWith('.md'))
   195|    .sort();
   196|
   197|  const plans = [];
   198|  for (const f of planFiles) {
   199|    const plan = await parsePlanFile(join(phaseDir, f));
   200|    plan.meta._sourceFile = join(phaseDir, f);
   201|    plans.push(plan);
   202|  }
   203|
   204|  return plans;
   205|}
   206|
   207|/**
   208| * Group tasks by wave number for parallel dispatch.
   209| *
   210| * @param {Task[]} tasks - Flat array of tasks
   211| * @returns {Map<number, Task[]>} Map of wave number → tasks in that wave
   212| */
   213|export function groupByWave(tasks) {
   214|  const waves = new Map();
   215|
   216|  for (const task of tasks) {
   217|    const w = typeof task.wave === 'number' ? task.wave : parseInt(task.wave, 10) || 1;
   218|    if (!waves.has(w)) waves.set(w, []);
   219|    waves.get(w).push(task);
   220|  }
   221|
   222|  // Return sorted by wave number
   223|  return new Map([...waves.entries()].sort((a, b) => a[0] - b[0]));
   224|}
   225|
   226|/**
   227| * Convenience: parse a plan and return tasks grouped by wave.
   228| *
   229| * @param {string} filePath - Path to PLAN.md
   230| * @returns {Promise<{meta: TaskMeta, mustBeTrue: string[], waves: Map<number, Task[]>}>}
   231| */
   232|export async function parsePlanByWaves(filePath) {
   233|  const plan = await parsePlanFile(filePath);
   234|  return {
   235|    meta: plan.meta,
   236|    mustBeTrue: plan.mustBeTrue,
   237|    waves: groupByWave(plan.tasks),
   238|  };
   239|}
