{"content": "     1|/**
     2| * @module commands/helpers
     3| * @description Shared utilities for GSD CLI commands — project discovery,
     4| * arg parsing, path resolution, template rendering.
     5| */
     6|
     7|import { readFile, readdir, mkdir, copyFile, stat } from 'node:fs/promises';
     8|import { join, resolve, dirname } from 'node:path';
     9|import { fileURLToPath } from 'node:url';
    10|
    11|const __dirname = dirname(fileURLToPath(import.meta.url));
    12|export const ROOT = resolve(__dirname, '..', '..');
    13|export const PROJECTS_DIR = join(ROOT, 'projects');
    14|export const TEMPLATES_DIR = join(ROOT, 'templates');
    15|
    16|/** Valid lifecycle stages in order */
    17|export const LIFECYCLE_STAGES = [
    18|  'DISCUSS', 'RESEARCH', 'PLAN', 'APPROVE', 'EXECUTE', 'VERIFY', 'SHIP', 'DONE',
    19|];
    20|
    21|/**
    22| * Parse CLI args into { positional: string[], flags: Record<string, string|true> }
    23| */
    24|export function parseArgs(argv = process.argv.slice(2)) {
    25|  const positional = [];
    26|  const flags = {};
    27|
    28|  for (let i = 0; i < argv.length; i++) {
    29|    const arg = argv[i];
    30|    if (arg.startsWith('--')) {
    31|      const key = arg.slice(2);
    32|      const next = argv[i + 1];
    33|      if (next && !next.startsWith('--')) {
    34|        flags[key] = next;
    35|        i++;
    36|      } else {
    37|        flags[key] = true;
    38|      }
    39|    } else {
    40|      positional.push(arg);
    41|    }
    42|  }
    43|
    44|  return { positional, flags };
    45|}
    46|
    47|/**
    48| * Get the .planning/ directory for a project.
    49| */
    50|export function planningDir(project) {
    51|  return join(PROJECTS_DIR, project, '.planning');
    52|}
    53|
    54|/**
    55| * Get the phases/ directory for a project.
    56| */
    57|export function phasesDir(project) {
    58|  return join(planningDir(project), 'phases');
    59|}
    60|
    61|/**
    62| * Check if a project exists (has a .planning/ directory).
    63| */
    64|export async function projectExists(project) {
    65|  try {
    66|    const s = await stat(planningDir(project));
    67|    return s.isDirectory();
    68|  } catch {
    69|    return false;
    70|  }
    71|}
    72|
    73|/**
    74| * List all project slugs that have .planning/ directories.
    75| */
    76|export async function listProjects() {
    77|  const entries = await readdir(PROJECTS_DIR, { withFileTypes: true });
    78|  const projects = [];
    79|
    80|  for (const entry of entries) {
    81|    if (!entry.isDirectory()) continue;
    82|    const planning = join(PROJECTS_DIR, entry.name, '.planning');
    83|    try {
    84|      const s = await stat(planning);
    85|      if (s.isDirectory()) projects.push(entry.name);
    86|    } catch {
    87|      // no .planning/ — skip
    88|    }
    89|  }
    90|
    91|  return projects.sort();
    92|}
    93|
    94|/**
    95| * Read a file or return null if it doesn't exist.
    96| */
    97|export async function readFileOrNull(path) {
    98|  try {
    99|    return await readFile(path, 'utf-8');
   100|  } catch {
   101|    return null;
   102|  }
   103|}
   104|
   105|/**
   106| * Read and render a template file, replacing {{key}} placeholders.
   107| */
   108|export async function renderTemplate(templateName, vars = {}) {
   109|  const raw = await readFile(join(TEMPLATES_DIR, templateName), 'utf-8');
   110|  return raw.replace(/\{\{(\w+)\}\}/g, (_, key) => vars[key] ?? `{{${key}}}`);
   111|}
   112|
   113|/**
   114| * Parse phases from a ROADMAP.md string.
   115| * Returns array of { id, name, goal, requirements, dependsOn, status, criteria }
   116| */
   117|export function parseRoadmapPhases(content) {
   118|  const phases = [];
   119|  const phaseRegex = /###\s*Phase\s+(\d+):\s*(.+)/g;
   120|  let match;
   121|
   122|  while ((match = phaseRegex.exec(content)) !== null) {
   123|    const num = match[1].padStart(2, '0');
   124|    const name = match[2].trim();
   125|    const startIdx = match.index + match[0].length;
   126|
   127|    // Find the end of this phase block (next ### or end of string)
   128|    const nextPhase = content.indexOf('\n### ', startIdx);
   129|    const nextH2 = content.indexOf('\n## ', startIdx);
   130|    const endIdx = Math.min(
   131|      nextPhase === -1 ? content.length : nextPhase,
   132|      nextH2 === -1 ? content.length : nextH2,
   133|    );
   134|    const block = content.slice(startIdx, endIdx);
   135|
   136|    const goalMatch = block.match(/\*\*Goal[^:]*:\*\*\s*(.+)/);
   137|    const reqMatch = block.match(/\*\*Requirements:\*\*\s*(.+)/);
   138|    const depMatch = block.match(/\*\*Depends On:\*\*\s*(.+)/);
   139|    const statusMatch = block.match(/\*\*Status:\*\*\s*(.+)/);
   140|
   141|    const criteria = [];
   142|    const criteriaSection = block.match(/\*\*Success Criteria:\*\*\n([\s\S]*?)(?=\n\*\*|\n###|\n##|$)/);
   143|    if (criteriaSection) {
   144|      for (const line of criteriaSection[1].split('\n')) {
   145|        const trimmed = line.replace(/^[-*]\s*/, '').trim();
   146|        if (trimmed) criteria.push(trimmed);
   147|      }
   148|    }
   149|
   150|    const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
   151|
   152|    phases.push({
   153|      id: `${num}-${slug}`,
   154|      num,
   155|      name,
   156|      goal: goalMatch ? goalMatch[1].trim() : '',
   157|      requirements: reqMatch ? reqMatch[1].trim() : '',
   158|      dependsOn: depMatch ? depMatch[1].trim() : 'none',
   159|      status: statusMatch ? statusMatch[1].trim() : 'planned',
   160|      criteria,
   161|    });
   162|  }
   163|
   164|  return phases;
   165|}
   166|
   167|/**
   168| * Find the current phase from STATE.md + ROADMAP.md.
   169| * Returns the phase object or null.
   170| */
   171|export function findCurrentPhase(state, roadmapPhases) {
   172|  if (state.currentPhase) {
   173|    return roadmapPhases.find(p => p.id === state.currentPhase) || roadmapPhases[0] || null;
   174|  }
   175|  // Default to first non-done phase
   176|  return roadmapPhases.find(p => p.status !== 'done') || roadmapPhases[0] || null;
   177|}
   178|
   179|/**
   180| * Pad a string to a fixed width (right-padded with spaces).
   181| */
   182|export function pad(str, width) {
   183|  const s = String(str);
   184|  return s.length >= width ? s : s + ' '.repeat(width - s.length);
   185|}
   186|
   187|/**
   188| * Print a formatted table to stdout.
   189| * @param {string[]} headers
   190| * @param {string[][]} rows
   191| */
   192|export function printTable(headers, rows) {
   193|  const widths = headers.map((h, i) =>
   194|    Math.max(h.length, ...rows.map(r => String(r[i] || '').length))
   195|  );
   196|
   197|  const sep = widths.map(w => '─'.repeat(w + 2)).join('┼');
   198|  const headerLine = headers.map((h, i) => ` ${pad(h, widths[i])} `).join('│');
   199|
   200|  console.log(headerLine);
   201|  console.log(sep);
   202|  for (const row of rows) {
   203|    console.log(row.map((c, i) => ` ${pad(c || '', widths[i])} `).join('│'));
   204|  }
   205|}
   206|
   207|/**
   208| * Fatal error — print message and exit with code.
   209| */
   210|export function fatal(msg, code = 1) {
   211|  console.error(`ERROR: ${msg}`);
   212|  process.exit(code);
   213|}
