{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * @command gsd-plan
     4| * @description Generate a PLAN.md template for the current phase.
     5| * Creates the phase directory and PLAN.md with task structure based on
     6| * ROADMAP.md phases and config.json routing.
     7| *
     8| * Usage:
     9| *   node src/commands/gsd-plan.js website-seo
    10| *   node src/commands/gsd-plan.js website-seo --phase 01-metadata-fixes
    11| */
    12|
    13|import { readFile, writeFile, mkdir } from 'node:fs/promises';
    14|import { join } from 'node:path';
    15|import { readState, updateState, setLifecycle, setPhaseAndWave, logDecision } from '../state.js';
    16|import {
    17|  parseArgs, planningDir, phasesDir, projectExists,
    18|  readFileOrNull, parseRoadmapPhases, findCurrentPhase,
    19|  renderTemplate, fatal,
    20|} from './helpers.js';
    21|
    22|/**
    23| * Load routing config for a project.
    24| * @param {string} project
    25| * @returns {Promise<Object>}
    26| */
    27|async function loadProjectConfig(project) {
    28|  const configPath = join(planningDir(project), 'config.json');
    29|  const raw = await readFileOrNull(configPath);
    30|  if (!raw) return null;
    31|  try {
    32|    return JSON.parse(raw);
    33|  } catch {
    34|    return null;
    35|  }
    36|}
    37|
    38|/**
    39| * Generate a task prefix from the phase name.
    40| * e.g., "metadata-fixes" → "META", "verification-polish" → "VRFY"
    41| */
    42|function generatePrefix(phaseName) {
    43|  const words = phaseName.replace(/[^a-zA-Z\s]/g, '').trim().split(/\s+/);
    44|  if (words.length === 1) {
    45|    return words[0].slice(0, 4).toUpperCase();
    46|  }
    47|  // Take first letter of each word, up to 4
    48|  return words.map(w => w[0]).join('').slice(0, 4).toUpperCase();
    49|}
    50|
    51|/**
    52| * Pick the default assignee for a task type from config routing.
    53| * @param {Object} config - Project config
    54| * @param {string} taskType - code | research | document | outreach | etc.
    55| * @returns {string} Assignee slug
    56| */
    57|function defaultAssignee(config, taskType) {
    58|  if (!config?.routing?.[taskType]) return 'hermes-ceo';
    59|  const candidates = config.routing[taskType];
    60|  return candidates[0] || 'hermes-ceo';
    61|}
    62|
    63|/**
    64| * Generate PLAN.md content for a phase.
    65| * Creates template tasks based on the phase's requirements and criteria.
    66| *
    67| * @param {Object} phase - Phase object from parseRoadmapPhases
    68| * @param {Object} config - Project config
    69| * @param {string} reqContent - Raw REQUIREMENTS.md content (for cross-reference)
    70| * @returns {string} PLAN.md content
    71| */
    72|export function generatePlanContent(phase, config, reqContent = '') {
    73|  const prefix = generatePrefix(phase.name);
    74|  const today = new Date().toISOString().split('T')[0];
    75|
    76|  const lines = [];
    77|
    78|  // Frontmatter
    79|  lines.push('---');
    80|  lines.push(`phase: ${phase.id}`);
    81|  lines.push(`title: ${phase.name}`);
    82|  lines.push(`goal: ${phase.goal}`);
    83|  lines.push('status: planned');
    84|  lines.push(`approval: ${config?.defaults?.approval || 'aaron'}`);
    85|  lines.push('wave: 1');
    86|  lines.push('---');
    87|  lines.push('');
    88|
    89|  // Header
    90|  lines.push(`# Plan: ${phase.name}`);
    91|  lines.push('');
    92|
    93|  // Must Be True
    94|  lines.push('## Must Be True');
    95|  if (phase.criteria.length > 0) {
    96|    for (const c of phase.criteria) {
    97|      lines.push(`- [ ] ${c}`);
    98|    }
    99|  } else {
   100|    lines.push(`- [ ] ${phase.goal || 'TBD — define conditions'}`);
   101|  }
   102|  lines.push('');
   103|
   104|  // Tasks section
   105|  lines.push('## Tasks');
   106|  lines.push('');
   107|
   108|  // Extract relevant requirements
   109|  const reqIds = (phase.requirements || '').split(',').map(r => r.trim()).filter(Boolean);
   110|  let taskNum = 0;
   111|
   112|  // Generate a research task (wave 1)
   113|  taskNum++;
   114|  const researchAssignee = defaultAssignee(config, 'research');
   115|  lines.push(`<task id="${prefix}-${String(taskNum).padStart(2, '0')}" type="research" assignee="${researchAssignee}" wave="1">`);
   116|  lines.push(`  <title>Research and audit for ${phase.name}</title>`);
   117|  lines.push(`  <description>Investigate current state and requirements for this phase. Review: ${reqIds.join(', ') || 'all requirements'}.</description>`);
   118|  lines.push(`  <verify>Research doc exists with findings and recommendations</verify>`);
   119|  lines.push(`  <done>Doc at .planning/research/${phase.id}.md</done>`);
   120|  lines.push('</task>');
   121|  lines.push('');
   122|
   123|  // Generate implementation tasks (wave 2) — one per success criterion
   124|  const criteria = phase.criteria.length > 0 ? phase.criteria : ['Implement phase requirements'];
   125|  for (const criterion of criteria) {
   126|    taskNum++;
   127|    const codeAssignee = defaultAssignee(config, 'code');
   128|    lines.push(`<task id="${prefix}-${String(taskNum).padStart(2, '0')}" type="code" assignee="${codeAssignee}" wave="2">`);
   129|    lines.push(`  <title>${criterion}</title>`);
   130|    lines.push(`  <description>Implement: ${criterion}</description>`);
   131|    lines.push(`  <verify>${criterion}</verify>`);
   132|    lines.push(`  <done>Changes committed and passing</done>`);
   133|    lines.push('</task>');
   134|    lines.push('');
   135|  }
   136|
   137|  // Generate a review/verify task (wave 3)
   138|  taskNum++;
   139|  const reviewAssignee = defaultAssignee(config, 'review');
   140|  lines.push(`<task id="${prefix}-${String(taskNum).padStart(2, '0')}" type="review" assignee="${reviewAssignee}" wave="3">`);
   141|  lines.push(`  <title>Review and verify ${phase.name}</title>`);
   142|  lines.push(`  <description>Verify all must-be-true conditions. Check that ${reqIds.join(', ') || 'requirements'} are satisfied.</description>`);
   143|  if (config?.defaults?.approval === 'aaron') {
   144|    lines.push('  <approval>aaron</approval>');
   145|  }
   146|  lines.push(`  <verify>All must-be-true conditions confirmed</verify>`);
   147|  lines.push(`  <done>Phase verified and approved</done>`);
   148|  lines.push('</task>');
   149|  lines.push('');
   150|
   151|  return lines.join('\n');
   152|}
   153|
   154|/**
   155| * Create a plan for a project phase.
   156| * @param {string} project
   157| * @param {string} [phaseOverride] - Specific phase ID to plan (e.g., "01-metadata-fixes")
   158| * @returns {Promise<{phaseId: string, planPath: string}>}
   159| */
   160|export async function createPlan(project, phaseOverride) {
   161|  const dir = planningDir(project);
   162|  const stateFile = join(dir, 'STATE.md');
   163|  const roadmapFile = join(dir, 'ROADMAP.md');
   164|  const reqFile = join(dir, 'REQUIREMENTS.md');
   165|
   166|  // Read roadmap
   167|  const roadmapContent = await readFileOrNull(roadmapFile);
   168|  if (!roadmapContent) {
   169|    fatal(`No ROADMAP.md found for "${project}". Run: gsd discuss ${project}`);
   170|  }
   171|
   172|  const phases = parseRoadmapPhases(roadmapContent);
   173|  if (phases.length === 0) {
   174|    fatal(`No phases defined in ROADMAP.md for "${project}". Define phases first.`);
   175|  }
   176|
   177|  // Determine which phase to plan
   178|  let phase;
   179|  if (phaseOverride) {
   180|    phase = phases.find(p => p.id === phaseOverride || p.num === phaseOverride);
   181|    if (!phase) {
   182|      fatal(`Phase "${phaseOverride}" not found. Available: ${phases.map(p => p.id).join(', ')}`);
   183|    }
   184|  } else {
   185|    // Read state to find current phase
   186|    const stateContent = await readFileOrNull(stateFile);
   187|    if (stateContent) {
   188|      const { parseStateContent } = await import('../state.js');
   189|      const state = parseStateContent(stateContent);
   190|      phase = findCurrentPhase(state, phases);
   191|    }
   192|    if (!phase) phase = phases[0];
   193|  }
   194|
   195|  // Load config and requirements
   196|  const config = await loadProjectConfig(project);
   197|  const reqContent = await readFileOrNull(reqFile) || '';
   198|
   199|  // Create phase directory
   200|  const phaseDir = join(phasesDir(project), phase.id);
   201|  await mkdir(phaseDir, { recursive: true });
   202|
   203|  // Generate and write PLAN.md
   204|  const planContent = generatePlanContent(phase, config, reqContent);
   205|  const planPath = join(phaseDir, 'PLAN.md');
   206|  await writeFile(planPath, planContent, 'utf-8');
   207|
   208|  // Update STATE.md
   209|  await updateState(stateFile, state => {
   210|    state.project = project;
   211|    setLifecycle(state, 'PLAN');
   212|    setPhaseAndWave(state, phase.id, 1);
   213|    logDecision(state, `Plan generated for phase ${phase.id}`, 'hermes-ceo');
   214|  });
   215|
   216|  console.log(`\n  ✓ Plan created: ${phase.id}`);
   217|  console.log(`  → ${planPath}`);
   218|  console.log(`\n  This is a TEMPLATE plan. Next steps:`);
   219|  console.log(`    1. Review and refine tasks in PLAN.md`);
   220|  console.log(`    2. Adjust assignees, waves, and verification criteria`);
   221|  console.log(`    3. Run: gsd execute ${project}`);
   222|  console.log('');
   223|
   224|  return { phaseId: phase.id, planPath };
   225|}
   226|
   227|/**
   228| * CLI entry point.
   229| */
   230|export async function main(argv) {
