    19|/**
    20| * Create a new project workspace from templates.
    21| * @param {string} project - Project slug
    22| * @param {string} goal - Project goal/description
    23| * @returns {Promise<void>}
    24| */
    25|export async function createProject(project, goal = '') {
    26|  const dir = planningDir(project);
    27|  const phases = phasesDir(project);
    28|  const today = new Date().toISOString().split('T')[0];
    29|  const prettyName = project.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    30|
    31|  // Create directories
    32|  await mkdir(dir, { recursive: true });
    33|  await mkdir(phases, { recursive: true });
    34|
    35|  const vars = {
    36|    project_slug: project,
    37|    project_name: prettyName,
    38|    created_date: today,
    39|    mc_project_id: '',
    40|    vision: goal || 'TBD — define during discussion phase',
    41|    core_value: goal || 'TBD',
    42|    constraint_1: 'TBD',
    43|    constraint_2: 'TBD',
    44|    success_1: 'TBD',
    45|    success_2: 'TBD',
    46|    success_3: 'TBD',
    47|    agent_1: 'TBD',
    48|    agent_1_role: 'TBD',
    49|    rationale: goal || 'New project',
    50|    phase_id: '',
    51|    total_phases: '0',
    52|    overview: goal || 'TBD — define phases during discussion',
    53|    phase_1_name: 'TBD',
    54|    phase_2_name: 'TBD',
    55|    goal_backward_statement: 'TBD',
    56|    effort_estimate: 'TBD',
    57|    criterion_1: 'TBD',
    58|    criterion_2: 'TBD',
    59|    req_title: 'TBD',
    60|    req_title_2: 'TBD',
    61|    type: 'code',
    62|    criteria: 'TBD',
    63|    description: 'TBD',
    64|    phase: 'TBD',
    65|    mc_api_key: '',
    66|  };
    67|
    68|  // Render and write each template
    69|  const templates = [
    70|    ['PROJECT.md.template', 'PROJECT.md'],
    71|    ['REQUIREMENTS.md.template', 'REQUIREMENTS.md'],
    72|    ['ROADMAP.md.template', 'ROADMAP.md'],
    73|    ['STATE.md.template', 'STATE.md'],
    74|    ['config.json.template', 'config.json'],
    75|  ];
    76|
    77|  for (const [template, output] of templates) {
    78|    const content = await renderTemplate(template, vars);
    79|    await writeFile(join(dir, output), content, 'utf-8');
    80|  }
    81|
    82|  // If a goal was provided, update PROJECT.md vision section
    83|  if (goal) {
    84|    const projectMd = join(dir, 'PROJECT.md');
    85|    let content = await readFile(projectMd, 'utf-8');
    86|    content = content.replace(/\{\{vision\}\}/g, goal);
    87|    content = content.replace(/\{\{core_value\}\}/g, goal);
    88|    await writeFile(projectMd, content, 'utf-8');
    89|  }
    90|
    91|  // Set STATE.md lifecycle to DISCUSS
    92|  const stateFile = join(dir, 'STATE.md');
    93|  await updateState(stateFile, state => {
    94|    state.project = project;
    95|    setLifecycle(state, 'DISCUSS');
