   100|  console.log(`  → ${dir}/`);
   101|  console.log(`    PROJECT.md, REQUIREMENTS.md, ROADMAP.md, STATE.md, config.json`);
   102|  console.log(`\n  Next: fill in PROJECT.md vision, then define REQUIREMENTS.md`);
   103|  console.log('');
