   105|
   106|/**
   107| * Show discussion context for an existing project.
   108| * @param {string} project
   109| * @returns {Promise<void>}
   110| */
   111|export async function showDiscussionContext(project) {
   112|  const dir = planningDir(project);
   113|  const prettyName = project.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
   114|
   115|  const projectMd = await readFileOrNull(join(dir, 'PROJECT.md'));
   116|  const reqMd = await readFileOrNull(join(dir, 'REQUIREMENTS.md'));
   117|  const roadmapMd = await readFileOrNull(join(dir, 'ROADMAP.md'));
   118|  const stateMd = await readFileOrNull(join(dir, 'STATE.md'));
   119|
   120|  console.log(`\n  ╔══════════════════════════════════════════╗`);
   121|  console.log(`  ║  DISCUSS: ${prettyName.padEnd(30)}  ║`);
   122|  console.log(`  ╚══════════════════════════════════════════╝\n`);
   123|
   124|  // What's decided
   125|  const decided = [];
   126|  const open = [];
   127|
   128|  if (projectMd) {
   129|    const hasVision = projectMd.includes('## Vision') && !projectMd.includes('TBD — define');
   130|    if (hasVision) decided.push('Vision defined');
   131|    else open.push('Vision needs definition in PROJECT.md');
   132|
   133|    const hasConstraints = projectMd.includes('## Constraints') && !projectMd.includes('{{constraint_');
   134|    if (hasConstraints) decided.push('Constraints established');
   135|    else open.push('Constraints need definition');
   136|
   137|    const hasSuccess = projectMd.includes('## Success Criteria') && !projectMd.includes('{{success_');
   138|    if (hasSuccess) decided.push('Success criteria set');
   139|    else open.push('Success criteria need definition');
   140|  } else {
   141|    open.push('PROJECT.md is missing');
   142|  }
   143|
   144|  if (reqMd) {
   145|    const reqCount = (reqMd.match(/### REQ-\d+/g) || []).length;
   146|    const filledReqs = (reqMd.match(/### REQ-\d+:\s*[^\n{]+/g) || []).length;
   147|    if (filledReqs > 0) decided.push(`${filledReqs} requirement(s) defined`);
   148|    if (reqCount > filledReqs) open.push(`${reqCount - filledReqs} requirement(s) need details`);
   149|    if (reqCount === 0) open.push('No requirements defined yet');
   150|  } else {
   151|    open.push('REQUIREMENTS.md is missing');
   152|  }
   153|
   154|  if (roadmapMd) {
   155|    const phases = parseRoadmapPhases(roadmapMd);
   156|    const definedPhases = phases.filter(p => p.name !== 'TBD' && !p.name.includes('{{'));
   157|    if (definedPhases.length > 0) decided.push(`${definedPhases.length} phase(s) in roadmap`);
   158|    else open.push('Roadmap phases need definition');
   159|  } else {
   160|    open.push('ROADMAP.md is missing');
   161|  }
   162|
   163|  // Print summary
   164|  if (decided.length > 0) {
   165|    console.log('  Decided:');
   166|    for (const d of decided) console.log(`    ✓ ${d}`);
   167|  }
   168|
   169|  if (open.length > 0) {
   170|    console.log('  Open:');
   171|    for (const o of open) console.log(`    ○ ${o}`);
   172|  }
   173|
   174|  // Advance lifecycle to DISCUSS if not already there
   175|  const stateFile = join(dir, 'STATE.md');
   176|  if (stateMd) {
   177|    await updateState(stateFile, state => {
   178|      if (state.lifecycle !== 'DISCUSS') {
   179|        setLifecycle(state, 'DISCUSS');
   180|      }
   181|    });
   182|  }
   183|
   184|  // Suggest next action
   185|  console.log('\n  Suggested next actions:');
   186|  if (open.length > 0) {
   187|    console.log(`    1. Resolve open items above`);
   188|    console.log(`    2. Run: gsd plan ${project}`);
   189|  } else {
   190|    console.log(`    → All items decided. Run: gsd plan ${project}`);
   191|  }
   192|  console.log('');
   193|}
   194|
   195|/**
   196| * CLI entry point.
   197| */
   198|export async function main(argv) {
   199|  const { positional, flags } = parseArgs(argv);
   200|
   201|  if (positional.length === 0) {
   202|    fatal('Usage: gsd discuss <project> [--goal "description"]', 2);
   203|  }
   204|
   205|  const project = positional[0];
   206|  const goal = flags.goal || '';
   207|  const exists = await projectExists(project);
   208|
   209|  if (!exists) {
