{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * @command gsd-execute
     4| * @description Dispatch tasks from the current phase PLAN.md to agent platforms.
     5| * Reads the plan, finds the next undispatched wave, and routes tasks via dispatcher.js.
     6| *
     7| * Usage:
     8| *   node src/commands/gsd-execute.js website-seo
     9| *   node src/commands/gsd-execute.js website-seo --wave 2
    10| *   node src/commands/gsd-execute.js website-seo --dry-run
    11| */
    12|
    13|import { readFile, readdir } from 'node:fs/promises';
    14|import { join } from 'node:path';
    15|import { parsePlanFile, groupByWave } from '../parser.js';
    16|import { dispatchTask, dispatchByWaves } from '../dispatcher.js';
    17|import { readState, updateState, setLifecycle, setPhaseAndWave, setTaskStatus, setTaskStatuses, logDecision, initTaskStatuses } from '../state.js';
    18|import { syncPlanToMC, syncStatusToMC } from '../mc-sync.js';
    19|import {
    20|  parseArgs, planningDir, phasesDir, projectExists,
    21|  readFileOrNull, pad, printTable, fatal,
    22|} from './helpers.js';
    23|
    24|/**
    25| * Find the PLAN.md file for the current phase.
    26| * Looks in .planning/phases/<phaseId>/ for PLAN.md or *PLAN.md
    27| * @param {string} project
    28| * @param {string} phaseId
    29| * @returns {Promise<string|null>} Path to PLAN.md
    30| */
    31|async function findPlanFile(project, phaseId) {
    32|  const phaseDir = join(phasesDir(project), phaseId);
    33|  try {
    34|    const entries = await readdir(phaseDir);
    35|    const planFile = entries.find(f => f.toUpperCase().includes('PLAN') && f.endsWith('.md'));
    36|    return planFile ? join(phaseDir, planFile) : null;
    37|  } catch {
    38|    return null;
    39|  }
    40|}
    41|
    42|/**
    43| * Find the next wave that has undispatched tasks.
    44| * @param {import('../parser.js').Task[]} tasks
    45| * @param {Object<string, string>} taskStatuses - Current task statuses
    46| * @returns {number|null} Wave number or null if all dispatched
    47| */
    48|function findNextWave(tasks, taskStatuses) {
    49|  const waves = groupByWave(tasks);
    50|  for (const [waveNum, waveTasks] of waves) {
    51|    const hasUndispatched = waveTasks.some(t => {
    52|      const status = taskStatuses[t.id];
    53|      return !status || status === 'planned';
    54|    });
    55|    if (hasUndispatched) return waveNum;
    56|  }
    57|  return null;
    58|}
    59|
    60|/**
    61| * Execute tasks for a project.
    62| * @param {string} project
    63| * @param {Object} options
    64| * @param {number} [options.wave] - Specific wave to dispatch
    65| * @param {boolean} [options.dryRun] - Don't actually dispatch
    66| * @returns {Promise<{dispatched: number, results: Object[]}>}
    67| */
    68|export async function executeProject(project, options = {}) {
    69|  const dir = planningDir(project);
    70|  const stateFile = join(dir, 'STATE.md');
    71|
    72|  // Read current state
    73|  const state = await readState(stateFile);
    74|  const phaseId = state.currentPhase;
    75|
    76|  if (!phaseId) {
    77|    fatal(`No current phase set for "${project}". Run: gsd plan ${project}`);
    78|  }
    79|
    80|  // Find PLAN.md
    81|  const planPath = await findPlanFile(project, phaseId);
    82|  if (!planPath) {
    83|    fatal(`No PLAN.md found for phase "${phaseId}". Run: gsd plan ${project}`);
    84|  }
    85|
    86|  // Parse plan
    87|  const plan = await parsePlanFile(planPath);
    88|  if (plan.tasks.length === 0) {
    89|    fatal(`No tasks found in ${planPath}`);
    90|  }
    91|
    92|  // Initialize task statuses if needed
    93|  initTaskStatuses(state, plan.tasks);
    94|
    95|  // Determine which wave to dispatch
    96|  const targetWave = options.wave || findNextWave(plan.tasks, state.taskStatuses);
    97|  if (targetWave === null) {
    98|    console.log(`\n  All waves dispatched for ${phaseId}.`);
    99|    console.log(`  Run: gsd verify ${project}`);
   100|    console.log('');
   101|    return { dispatched: 0, results: [] };
   102|  }
   103|
   104|  // Get tasks for this wave
   105|  const waves = groupByWave(plan.tasks);
   106|  const waveTasks = waves.get(targetWave) || [];
   107|
   108|  if (waveTasks.length === 0) {
   109|    fatal(`No tasks in wave ${targetWave}`);
   110|  }
   111|
   112|  // Filter to only undispatched tasks
   113|  const toDispatch = waveTasks.filter(t => {
   114|    const status = state.taskStatuses[t.id];
   115|    return !status || status === 'planned';
   116|  });
   117|
   118|  if (toDispatch.length === 0) {
   119|    console.log(`\n  Wave ${targetWave}: all tasks already dispatched.`);
   120|    const nextWave = findNextWave(plan.tasks, state.taskStatuses);
   121|    if (nextWave) {
   122|      console.log(`  Next undispatched wave: ${nextWave}`);
   123|    } else {
   124|      console.log(`  All waves dispatched. Run: gsd verify ${project}`);
   125|    }
   126|    console.log('');
   127|    return { dispatched: 0, results: [] };
   128|  }
   129|
   130|  console.log(`\n  Executing: ${phaseId} — Wave ${targetWave}`);
