   132|
   133|  // Dispatch each task
   134|  const results = [];
   135|  for (const task of toDispatch) {
   136|    const result = await dispatchTask(task, { dryRun: options.dryRun });
   137|    results.push(result);
   138|
   139|    const statusIcon = result.success ? '✓' : '✗';
   140|    console.log(`  ${statusIcon} ${pad(task.id, 10)} → ${result.platform} (${task.assignee})`);
   141|    if (!result.success && result.error) {
   142|      console.log(`    Error: ${result.error}`);
