{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * @command gsd-verify
     4| * @description Verify completed tasks against their verification criteria.
     5| * Reads PLAN.md, checks task statuses from STATE.md, and produces a verification report.
     6| *
     7| * Usage:
     8| *   node src/commands/gsd-verify.js website-seo
     9| */
    10|
    11|import { readFile, readdir } from 'node:fs/promises';
    12|import { join } from 'node:path';
    13|import { parsePlanFile } from '../parser.js';
    14|import { readState, updateState, setLifecycle, setPhaseAndWave, setTaskStatus, logDecision } from '../state.js';
    15|import { syncStatusToMC } from '../mc-sync.js';
    16|import {
    17|  parseArgs, planningDir, phasesDir, projectExists,
    18|  readFileOrNull, parseRoadmapPhases, pad, printTable, fatal,
    19|} from './helpers.js';
    20|
    21|/**
    22| * Find the PLAN.md file for a phase.
    23| */
    24|async function findPlanFile(project, phaseId) {
    25|  const phaseDir = join(phasesDir(project), phaseId);
    26|  try {
    27|    const entries = await readdir(phaseDir);
    28|    const planFile = entries.find(f => f.toUpperCase().includes('PLAN') && f.endsWith('.md'));
    29|    return planFile ? join(phaseDir, planFile) : null;
    30|  } catch {
    31|    return null;
    32|  }
    33|}
    34|
    35|/**
    36| * Assess a task's verification status.
    37| * Returns { status, reason }
    38| */
    39|function assessTask(task, stateStatus) {
    40|  // Not started or still in progress
    41|  if (!stateStatus || stateStatus === 'planned' || stateStatus === 'dispatched') {
    42|    return { status: 'pending', reason: `Status: ${stateStatus || 'planned'} — not yet complete` };
    43|  }
    44|
    45|  if (stateStatus === 'blocked') {
    46|    return { status: 'blocked', reason: 'Task is blocked' };
    47|  }
    48|
    49|  if (stateStatus === 'verified') {
    50|    return { status: 'verified', reason: 'Already verified' };
    51|  }
    52|
    53|  // Task is done — check verification criteria
    54|  if (stateStatus === 'done' || stateStatus === 'in_progress') {
    55|    if (!task.verify) {
    56|      return { status: 'needs_review', reason: 'No verification criteria defined' };
    57|    }
    58|
    59|    // Check if approval is required
    60|    if (task.approval) {
    61|      return {
    62|        status: 'needs_approval',
    63|        reason: `Requires approval from: ${task.approval}`,
    64|      };
    65|    }
    66|
    67|    return {
    68|      status: 'needs_review',
    69|      reason: `Verify: ${task.verify}`,
    70|    };
    71|  }
    72|
    73|  return { status: 'unknown', reason: `Unrecognized status: ${stateStatus}` };
    74|}
    75|
    76|/**
    77| * Run verification for a project's current phase.
    78| * @param {string} project
    79| * @returns {Promise<Object>} Verification report
    80| */
    81|export async function verifyProject(project) {
    82|  const dir = planningDir(project);
    83|  const stateFile = join(dir, 'STATE.md');
    84|  const roadmapFile = join(dir, 'ROADMAP.md');
    85|
    86|  const state = await readState(stateFile);
    87|  const phaseId = state.currentPhase;
    88|
    89|  if (!phaseId) {
    90|    fatal(`No current phase set for "${project}". Run: gsd plan ${project}`);
    91|  }
    92|
    93|  // Find and parse PLAN.md
    94|  const planPath = await findPlanFile(project, phaseId);
    95|  if (!planPath) {
    96|    fatal(`No PLAN.md found for phase "${phaseId}".`);
    97|  }
    98|
    99|  const plan = await parsePlanFile(planPath);
   100|  if (plan.tasks.length === 0) {
   101|    fatal(`No tasks in ${planPath}`);
   102|  }
   103|
   104|  console.log(`\n  Verification Report: ${phaseId}`);
   105|  console.log(`  ${'─'.repeat(50)}\n`);
   106|
   107|  // Assess each task
   108|  const report = {
   109|    phaseId,
   110|    total: plan.tasks.length,
   111|    verified: 0,
   112|    done: 0,
   113|    needsReview: 0,
   114|    needsApproval: 0,
   115|    pending: 0,
   116|    blocked: 0,
   117|    tasks: [],
   118|  };
   119|
   120|  const rows = [];
   121|  for (const task of plan.tasks) {
   122|    const stateStatus = state.taskStatuses[task.id] || 'planned';
   123|    const assessment = assessTask(task, stateStatus);
   124|
   125|    report.tasks.push({
   126|      id: task.id,
   127|      title: task.title,
   128|      stateStatus,
   129|      assessment: assessment.status,
   130|      reason: assessment.reason,
   131|      verify: task.verify,
   132|    });
   133|
   134|    switch (assessment.status) {
   135|      case 'verified': report.verified++; break;
   136|      case 'done': report.done++; break;
   137|      case 'needs_review': report.needsReview++; break;
   138|      case 'needs_approval': report.needsApproval++; break;
   139|      case 'pending': report.pending++; break;
   140|      case 'blocked': report.blocked++; break;
   141|    }
   142|
   143|    const icon = {
   144|      verified: '✓',
   145|      done: '●',
   146|      needs_review: '?',
   147|      needs_approval: '⊘',
   148|      pending: '○',
   149|      blocked: '✗',
   150|    }[assessment.status] || '?';
   151|
   152|    rows.push([icon, task.id, stateStatus, assessment.status, assessment.reason.slice(0, 50)]);
   153|  }
   154|
   155|  printTable(
   156|    ['', 'Task', 'State', 'Verdict', 'Detail'],
   157|    rows,
   158|  );
   159|
   160|  // Must-be-true conditions
   161|  if (plan.mustBeTrue.length > 0) {
   162|    console.log(`\n  Must Be True:`);
   163|    for (const condition of plan.mustBeTrue) {
   164|      const allDone = report.verified + report.done >= report.total - report.pending;
   165|      const icon = allDone ? '✓' : '○';
   166|      console.log(`    ${icon} ${condition}`);
   167|    }
   168|  }
   169|
   170|  // Summary
   171|  const allVerified = report.verified === report.total;
   172|  const allDone = (report.verified + report.done + report.needsReview + report.needsApproval) === report.total && report.pending === 0;
   173|
   174|  console.log(`\n  Summary:`);
   175|  console.log(`    Verified:       ${report.verified}/${report.total}`);
   176|  console.log(`    Needs Review:   ${report.needsReview}`);
   177|  console.log(`    Needs Approval: ${report.needsApproval}`);
   178|  console.log(`    Pending:        ${report.pending}`);
   179|  console.log(`    Blocked:        ${report.blocked}`);
   180|
   181|  // Determine next action
   182|  if (allVerified) {
   183|    console.log(`\n  ✓ All tasks verified! Phase ${phaseId} is complete.`);
   184|
   185|    // Check for next phase
   186|    const roadmapContent = await readFileOrNull(roadmapFile);
   187|    const phases = roadmapContent ? parseRoadmapPhases(roadmapContent) : [];
   188|    const currentIdx = phases.findIndex(p => p.id === phaseId);
   189|    const nextPhase = currentIdx >= 0 && currentIdx < phases.length - 1
   190|      ? phases[currentIdx + 1]
   191|      : null;
   192|
   193|    // Update state
   194|    await updateState(stateFile, s => {
   195|      s.project = project;
   196|      if (nextPhase) {
   197|        setLifecycle(s, 'DISCUSS');
   198|        setPhaseAndWave(s, nextPhase.id, 1);
   199|        logDecision(s, `Phase ${phaseId} verified. Advancing to ${nextPhase.id}`, 'hermes-ceo');
   200|      } else {
   201|        setLifecycle(s, 'DONE');
   202|        logDecision(s, `Phase ${phaseId} verified. Project complete.`, 'hermes-ceo');
   203|      }
   204|    });
   205|
   206|    if (nextPhase) {
   207|      console.log(`  → Next phase: ${nextPhase.id} (${nextPhase.name})`);
   208|      console.log(`    Run: gsd discuss ${project}`);
   209|    } else {
   210|      console.log(`  → Project lifecycle: DONE`);
   211|    }
   212|  } else if (allDone) {
   213|    // All tasks done but not all verified — advance to VERIFY
   214|    await updateState(stateFile, s => {
   215|      s.project = project;
   216|      setLifecycle(s, 'VERIFY');
   217|      logDecision(s, `Phase ${phaseId}: all tasks complete, verification in progress`, 'hermes-ceo');
   218|    });
   219|
   220|    console.log(`\n  Phase tasks complete. Manual verification needed for ${report.needsReview + report.needsApproval} task(s).`);
   221|    if (report.needsApproval > 0) {
   222|      console.log(`  ${report.needsApproval} task(s) need approval.`);
   223|    }
   224|  } else {
   225|    console.log(`\n  ${report.pending} task(s) still pending. Run: gsd execute ${project}`);
   226|  }
   227|
   228|  console.log('');
   229|
   230|  // Sync to MC (best effort)
   231|  try {
   232|    const statusUpdates = {};
   233|    for (const t of report.tasks) {
   234|      if (t.assessment === 'verified') statusUpdates[t.id] = 'verified';
   235|    }
   236|    if (Object.keys(statusUpdates).length > 0) {
   237|      await syncStatusToMC(statusUpdates);
   238|    }
   239|  } catch { /* best effort */ }
   240|
   241|  return report;
   242|}
   243|
   244|/**
   245| * CLI entry point.
   246| */
   247|export async function main(argv) {
   248|  const { positional } = parseArgs(argv);
   249|
   250|  if (positional.length === 0) {
   251|    fatal('Usage: gsd verify <project>', 2);
   252|  }
   253|
   254|  const project = positional[0];
   255|  if (!(await projectExists(project))) {
   256|    fatal(`Project "${project}" not found.`, 1);
   257|  }
   258|
   259|  await verifyProject(project);
   260|}
   261|
   262|// Run if called directly
   263|const isMain = process.argv[1] && (
   264|  process.argv[1].endsWith('gsd-verify.js') ||
   265|  process.argv[1].endsWith('gsd-verify')
   266|);
   267|if (isMain) {
   268|  main().catch(err => { console.error(err.message); process.exit(1); });
   269|}
